window.BEZALEL_FIRESTORESYNC_GS = "// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// FIRESTORE \u2192 SHEET HOURLY SYNC (FirestoreSync.gs)\n//\n// Reads all documents from Firestore collections under churches/{CHURCH_ID}\n// and writes them back to the matching Google Sheet tabs as a live backup.\n//\n// Collections synced: members, careCases\n//   (Add more collections to SYNC_COLLECTIONS below as needed.)\n//\n// Church ID is auto-resolved (see _resolveFirestoreChurchId):\n//   1. FIRESTORE_CHURCH_ID script property   (explicit override)\n//   2. ChurchRegistry tab, ShortName col G   (auto from sheet)\n//   3. DEPLOY_CONFIG.churchName              (fallback)\n//   4. 'FlockOS'                             (default)\n//\n// Requires FIREBASE_SERVICE_ACCOUNT in Script Properties\n// (same one used for Firebase custom tokens).\n//\n// Setup (see Master Code header for full deployment steps):\n//   1. Run syncFirestoreToSheet() once manually to test\n//   2. Run installFirestoreSyncTrigger() to start hourly backups\n//   3. Run removeFirestoreSyncTrigger() to stop\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n\n// \u2500\u2500 Config \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n//\n// FIRESTORE_PROJECT_ID  (Script Property) \u2014 Firestore project for this church.\n//   Default: 'flockos-notify'  (shared FlockOS project)\n//   Override: set to 'flockos-trinity', 'flockos-theforest', etc. for isolated projects\n//\n// TRUTH_FIRESTORE_PROJECT_ID  (Script Property) \u2014 The master Truth content project.\n//   Default: 'flockos-truth'\n//\n// TRUTH_SERVICE_ACCOUNT  (Script Property) \u2014 Service account JSON for flockos-truth.\n//   Required for replicateTruthFromMaster() and populateTruthMaster().\n//   Obtain from: Firebase Console \u2192 flockos-truth \u2192 Project Settings \u2192 Service accounts\n\nvar FS_PROJECT_ID     = (PropertiesService.getScriptProperties().getProperty('FIRESTORE_PROJECT_ID')       || 'flockos-notify').trim();\nvar TRUTH_PROJECT_ID  = (PropertiesService.getScriptProperties().getProperty('TRUTH_FIRESTORE_PROJECT_ID') || 'flockos-truth').trim();\n\n/**\n * Resolves the Firestore church ID for this deployment.\n * Checks (in order):\n *   1. FIRESTORE_CHURCH_ID script property  (explicit override)\n *   2. ChurchRegistry tab, column G (ShortName) from the first data row\n *   3. DEPLOY_CONFIG.churchName  (fallback)\n *   4. 'FlockOS'  (default)\n */\nfunction _resolveFirestoreChurchId() {\n  var props = PropertiesService.getScriptProperties();\n\n  // 1. Explicit script property (accepts FIRESTORE_CHURCH_ID or FIREBASE_CHURCH_ID)\n  var explicit = (props.getProperty('FIRESTORE_CHURCH_ID') || props.getProperty('FIREBASE_CHURCH_ID') || '').trim();\n  if (explicit) return explicit;\n\n  // 2. ChurchRegistry tab \u2192 first row ShortName (col G)\n  try {\n    var ss = SpreadsheetApp.openById(props.getProperty('SHEET_ID'));\n    var reg = ss.getSheetByName('ChurchRegistry');\n    if (reg && reg.getLastRow() >= 2) {\n      var shortName = String(reg.getRange(2, 7).getValue() || '').trim(); // col G = ShortName\n      if (shortName) return shortName;\n      var churchId = String(reg.getRange(2, 1).getValue() || '').trim();  // col A = ChurchID\n      if (churchId) return churchId;\n    }\n  } catch (_) {}\n\n  // 3. DEPLOY_CONFIG\n  if (typeof DEPLOY_CONFIG !== 'undefined' && DEPLOY_CONFIG.churchName) {\n    return DEPLOY_CONFIG.churchName.trim();\n  }\n\n  // 4. Default\n  return 'FlockOS';\n}\n\n/**\n * Each entry maps a Firestore collection \u2192 Sheet tab + column order.\n * The 'fields' array defines the exact column order in the sheet.\n * Headers are written to row 1; data starts at row 2.\n */\nvar SYNC_COLLECTIONS = {\n\n  members: {\n    tab: 'Members',\n    fields: [\n      'memberPin', 'firstName', 'lastName', 'preferredName', 'suffix',\n      'dateOfBirth', 'gender', 'photoUrl', 'primaryEmail', 'secondaryEmail',\n      'cellPhone', 'homePhone', 'workPhone', 'preferredContact',\n      'address1', 'address2', 'city', 'state', 'zip', 'country',\n      'membershipStatus', 'memberSince', 'howTheyFoundUs',\n      'baptismDate', 'salvationDate', 'dateOfDeath',\n      'householdId', 'familyRole', 'maritalStatus', 'spouseName',\n      'emergencyContact', 'emergencyPhone',\n      'ministryTeams', 'volunteerRoles', 'spiritualGifts', 'smallGroup',\n      'pastoralNotes', 'lastContactDate', 'nextFollowUp', 'followUpPriority',\n      'assignedTo', 'tags', 'archived', 'archiveReason',\n      'createdBy', 'createdAt', 'updatedBy', 'updatedAt',\n      'website', 'colorScheme', 'bgScheme', 'id'\n    ],\n    headers: [\n      'ID', 'First Name', 'Last Name', 'Preferred Name', 'Suffix',\n      'Date of Birth', 'Gender', 'Photo URL', 'Primary Email', 'Secondary Email',\n      'Cell Phone', 'Home Phone', 'Work Phone', 'Preferred Contact',\n      'Street Address 1', 'Street Address 2', 'City', 'State', 'ZIP Code', 'Country',\n      'Membership Status', 'Member Since', 'How They Found Us',\n      'Baptism Date', 'Salvation Date', 'Date of Death',\n      'Household ID', 'Family Role', 'Marital Status', 'Spouse Name',\n      'Emergency Contact', 'Emergency Phone',\n      'Ministry Teams', 'Volunteer Roles', 'Spiritual Gifts', 'Small Group',\n      'Pastoral Notes', 'Last Contact Date', 'Next Follow-Up', 'Follow-Up Priority',\n      'Assigned To', 'Tags', 'Archived', 'Archive Reason',\n      'Created By', 'Created At', 'Updated By', 'Updated At',\n      'Website Link', 'Color Scheme', 'BG Scheme', 'firestoreId'\n    ]\n  },\n\n  careCases: {\n    tab: 'SpiritualCareCases',\n    fields: [\n      'id', 'memberId', 'careType', 'priority', 'status',\n      'summary', 'assignedTeamId', 'primaryCaregiverId', 'secondaryCaregiverId',\n      'openedDate', 'targetResolveDate', 'resolvedDate',\n      'referralInfo', 'confidential', 'notes',\n      'riskLevel', 'supportPresence', 'spiritualState', 'trend',\n      'linkedCaseId', 'nextReviewDate',\n      'createdBy', 'createdAt', 'updatedBy', 'updatedAt'\n    ],\n    headers: [\n      'ID', 'Member ID', 'Care Type', 'Priority', 'Status',\n      'Summary', 'Assigned Team ID', 'Primary Caregiver ID', 'Secondary Caregiver ID',\n      'Opened Date', 'Target Resolve Date', 'Resolved Date',\n      'Referral Info', 'Confidential', 'Notes',\n      'Risk Level', 'Support Presence', 'Spiritual State', 'Trend',\n      'Linked Case ID', 'Next Review Date',\n      'Created By', 'Created At', 'Updated By', 'Updated At'\n    ]\n  }\n};\n\n\n// \u2500\u2500 Connection Test \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n/**\n * Verifies the Firestore connection for this church's project.\n * Run this from the GAS editor dropdown BEFORE running any sync or migration.\n *\n * Checks:\n *   1. FIREBASE_SERVICE_ACCOUNT is present and parseable\n *   2. OAuth2 access token is obtained successfully\n *   3. Firestore REST API responds to a lightweight listDocuments request\n *   4. Logs the church ID and project ID being used\n */\nfunction testFirestoreConnection() {\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n  Logger.log('  FlockOS \u2014 Firestore Connection Test');\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n\n  // \u2500\u2500 1. Resolve IDs \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  var projectId = FS_PROJECT_ID;\n  var churchId  = _resolveFirestoreChurchId();\n  Logger.log('  Project ID  : ' + projectId);\n  Logger.log('  Church ID   : ' + churchId);\n\n  // \u2500\u2500 2. Check service account property \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  var saJson = PropertiesService.getScriptProperties().getProperty('FIREBASE_SERVICE_ACCOUNT')\n            || PropertiesService.getScriptProperties().getProperty('FIRESTORE_SERVICE_ACCOUNT');\n  if (!saJson) {\n    Logger.log('\u274c FIREBASE_SERVICE_ACCOUNT (or FIRESTORE_SERVICE_ACCOUNT) script property is missing.');\n    return;\n  }\n  try {\n    JSON.parse(saJson);\n    Logger.log('  Service acct: \u2705 Found and parseable');\n  } catch(e) {\n    Logger.log('\u274c FIREBASE_SERVICE_ACCOUNT is not valid JSON: ' + e.message);\n    return;\n  }\n\n  // \u2500\u2500 3. Get access token \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  var token;\n  try {\n    token = _getFirestoreAccessToken();\n    Logger.log('  Auth token  : \u2705 Obtained');\n  } catch(e) {\n    Logger.log('\u274c Failed to get access token: ' + e.message);\n    return;\n  }\n\n  // \u2500\u2500 4. Ping Firestore \u2014 list root-level collections \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  var url = 'https://firestore.googleapis.com/v1/projects/' + projectId +\n            '/databases/(default)/documents/settings/sync' +\n            '?mask.fieldPaths=__name__';\n  try {\n    var resp = UrlFetchApp.fetch(url, {\n      headers: { 'Authorization': 'Bearer ' + token },\n      muteHttpExceptions: true\n    });\n    var code = resp.getResponseCode();\n    if (code === 200) {\n      Logger.log('  Firestore   : \u2705 Connected \u2014 settings/sync exists');\n    } else if (code === 404) {\n      Logger.log('  Firestore   : \u2705 Connected \u2014 project reachable (settings/sync not yet written)');\n    } else {\n      Logger.log('  Firestore   : \u26a0\ufe0f  HTTP ' + code + ' \u2014 ' + resp.getContentText().substring(0, 200));\n    }\n  } catch(e) {\n    Logger.log('\u274c Firestore request failed: ' + e.message);\n    return;\n  }\n\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n  Logger.log('  \u2705 Connection test complete.');\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n}\n\n\n// \u2500\u2500 Main Sync Function \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nfunction syncFirestoreToSheet() {\n  var churchId = _resolveFirestoreChurchId();\n  var token    = _getFirestoreAccessToken();\n  var ss       = SpreadsheetApp.openById(\n    PropertiesService.getScriptProperties().getProperty('SHEET_ID')\n  );\n\n  Logger.log('[FirestoreSync] Church ID: ' + churchId);\n  var totalDocs = 0;\n\n  var collNames = Object.keys(SYNC_COLLECTIONS);\n  for (var c = 0; c < collNames.length; c++) {\n    var collName = collNames[c];\n    var config   = SYNC_COLLECTIONS[collName];\n\n    Logger.log('[FirestoreSync] Reading ' + collName + '...');\n\n    // Fetch all documents from Firestore\n    var docs = _firestoreListAll(collName, token);\n    Logger.log('[FirestoreSync] ' + collName + ': ' + docs.length + ' documents');\n\n    // Get or create the sheet tab lazily \u2014 tabs are not pre-built during setup,\n    // they emerge when data actually arrives from Firestore for the first time.\n    var sheet = _getOrCreateSheet_(ss, config.tab, config.headers);\n\n    // Build rows: headers + data\n    var rows = [config.headers];\n    for (var d = 0; d < docs.length; d++) {\n      var doc = docs[d];\n      var row = [];\n      for (var f = 0; f < config.fields.length; f++) {\n        var val = doc[config.fields[f]];\n        row.push(val !== undefined && val !== null ? val : '');\n      }\n      rows.push(row);\n    }\n\n    // Clear and write\n    sheet.clearContents();\n    if (rows.length > 0 && rows[0].length > 0) {\n      // Ensure sheet has enough rows/cols\n      if (sheet.getMaxRows() < rows.length) {\n        sheet.insertRowsAfter(sheet.getMaxRows(), rows.length - sheet.getMaxRows());\n      }\n      if (sheet.getMaxColumns() < rows[0].length) {\n        sheet.insertColumnsAfter(sheet.getMaxColumns(), rows[0].length - sheet.getMaxColumns());\n      }\n      sheet.getRange(1, 1, rows.length, rows[0].length).setValues(rows);\n    }\n\n    totalDocs += docs.length;\n  }\n\n  SpreadsheetApp.flush();\n  Logger.log('[FirestoreSync] \u2705 Sync complete \u2014 ' + totalDocs + ' total documents written across ' + collNames.length + ' tabs.');\n}\n\n\n// \u2500\u2500 Firestore REST API \u2014 list all documents in a collection \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nfunction _firestoreListAll(collectionName, accessToken) {\n  var baseUrl = 'https://firestore.googleapis.com/v1/projects/' + FS_PROJECT_ID +\n    '/databases/(default)/documents/' + collectionName;\n\n  var allDocs = [];\n  var pageToken = null;\n\n  do {\n    var url = baseUrl + '?pageSize=300';\n    if (pageToken) url += '&pageToken=' + pageToken;\n\n    var resp = UrlFetchApp.fetch(url, {\n      method: 'get',\n      headers: { 'Authorization': 'Bearer ' + accessToken },\n      muteHttpExceptions: true\n    });\n\n    var code = resp.getResponseCode();\n    if (code !== 200) {\n      Logger.log('[FirestoreSync] ERROR fetching ' + collectionName + ': HTTP ' + code);\n      Logger.log(resp.getContentText().substring(0, 500));\n      break;\n    }\n\n    var body = JSON.parse(resp.getContentText());\n    var documents = body.documents || [];\n\n    for (var i = 0; i < documents.length; i++) {\n      var fsDoc = documents[i];\n      var parsed = _parseFirestoreDoc(fsDoc);\n      // Extract doc ID from the name path\n      var nameParts = fsDoc.name.split('/');\n      parsed.id = nameParts[nameParts.length - 1];\n      allDocs.push(parsed);\n    }\n\n    pageToken = body.nextPageToken || null;\n  } while (pageToken);\n\n  return allDocs;\n}\n\n\n// \u2500\u2500 Parse a Firestore document's fields into a plain JS object \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nfunction _parseFirestoreDoc(fsDoc) {\n  var fields = fsDoc.fields || {};\n  var obj = {};\n  var keys = Object.keys(fields);\n  for (var i = 0; i < keys.length; i++) {\n    var key = keys[i];\n    obj[key] = _parseFirestoreValue(fields[key]);\n  }\n  return obj;\n}\n\nfunction _parseFirestoreValue(val) {\n  if (val.stringValue  !== undefined) return val.stringValue;\n  if (val.integerValue !== undefined) return Number(val.integerValue);\n  if (val.doubleValue  !== undefined) return val.doubleValue;\n  if (val.booleanValue !== undefined) return val.booleanValue;\n  if (val.timestampValue !== undefined) return val.timestampValue;\n  if (val.nullValue    !== undefined) return '';\n  if (val.mapValue) return JSON.stringify(_parseFirestoreDoc({ fields: val.mapValue.fields }));\n  if (val.arrayValue) {\n    var arr = (val.arrayValue.values || []);\n    var result = [];\n    for (var i = 0; i < arr.length; i++) {\n      result.push(_parseFirestoreValue(arr[i]));\n    }\n    return result.join(', ');\n  }\n  return '';\n}\n\n\n// \u2500\u2500 Get an OAuth2 access token using the service account \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nfunction _getFirestoreAccessToken() {\n  var props = PropertiesService.getScriptProperties();\n  var saJson = props.getProperty('FIREBASE_SERVICE_ACCOUNT') || props.getProperty('FIRESTORE_SERVICE_ACCOUNT');\n  if (!saJson) throw new Error('FIREBASE_SERVICE_ACCOUNT (or FIRESTORE_SERVICE_ACCOUNT) not set in Script Properties');\n\n  var sa = JSON.parse(saJson);\n  var saEmail    = sa.client_email;\n  var privateKey = sa.private_key;\n\n  var now = Math.floor(Date.now() / 1000);\n\n  // JWT for Google OAuth2 token exchange\n  var header = { alg: 'RS256', typ: 'JWT' };\n  var claimSet = {\n    iss:   saEmail,\n    scope: 'https://www.googleapis.com/auth/datastore',\n    aud:   'https://oauth2.googleapis.com/token',\n    iat:   now,\n    exp:   now + 3600\n  };\n\n  var b64Header = Utilities.base64EncodeWebSafe(JSON.stringify(header)).replace(/=+$/, '');\n  var b64Claims = Utilities.base64EncodeWebSafe(JSON.stringify(claimSet)).replace(/=+$/, '');\n  var sigInput  = b64Header + '.' + b64Claims;\n\n  var signature = Utilities.computeRsaSha256Signature(sigInput, privateKey);\n  var b64Sig    = Utilities.base64EncodeWebSafe(signature).replace(/=+$/, '');\n\n  var jwt = sigInput + '.' + b64Sig;\n\n  // Exchange JWT for access token\n  var tokenResp = UrlFetchApp.fetch('https://oauth2.googleapis.com/token', {\n    method: 'post',\n    payload: {\n      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',\n      assertion: jwt\n    },\n    muteHttpExceptions: true\n  });\n\n  var tokenBody = JSON.parse(tokenResp.getContentText());\n  if (!tokenBody.access_token) {\n    throw new Error('Failed to get Firestore access token: ' + tokenResp.getContentText());\n  }\n\n  return tokenBody.access_token;\n}\n\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// TRUTH CONTENT \u2192 FIRESTORE SEEDING\n//\n// Reads the 12 Truth content tabs from the church's own Google Sheet and\n// pushes every row to Firestore under  churches/{churchId}/{collection}.\n//\n// Called automatically during setupFlockOS() \u2014 can also be run standalone\n// from the Apps Script editor to re-seed an existing church.\n//\n// Requires FIREBASE_SERVICE_ACCOUNT in Script Properties.\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n\n/**\n * Maps each Truth sheet tab \u2192 Firestore collection name, header\u2192field mappings,\n * and document-ID strategy.\n *\n * docIdHeader  \u2014 column header whose value becomes the Firestore doc ID.\n *                null  = auto-generate a deterministic row-based ID.\n * docIdPrefix  \u2014 prefix for auto-generated IDs (e.g. \"apol\" \u2192 \"apol_001\").\n */\nvar TRUTH_FIRESTORE_MAP = {\n\n  'Apologetics': {\n    collection: 'apologetics',\n    docIdHeader: null,\n    docIdPrefix: 'apol',\n    headerMap: {\n      'Category ID': 'categoryId', 'Category Title': 'categoryTitle',\n      'Category Color': 'categoryColor', 'Category Intro': 'categoryIntro',\n      'Question ID': 'questionId', 'Question Title': 'questionTitle',\n      'Short Title': 'shortTitle', 'Answer Content': 'answerContent',\n      'Quote Text': 'quoteText', 'Reference Text': 'referenceText',\n      'Reference URL': 'referenceUrl'\n    }\n  },\n\n  'Books': {\n    collection: 'books',\n    docIdHeader: 'ID / Book Number',\n    headerMap: {\n      'Book Name': 'bookName', 'Testament': 'testament', 'Genre': 'genre',\n      'Summary': 'summary', 'Core Theology': 'coreTheology',\n      'Practical Application': 'practicalApplication',\n      'ID / Book Number': 'bookId'\n    }\n  },\n\n  'Counseling': {\n    collection: 'counseling',\n    docIdHeader: 'ID',\n    headerMap: {\n      'Title': 'title', 'Icon': 'icon', 'Color': 'color',\n      'Definition': 'definition', 'Scriptures': 'scriptures',\n      'Steps': 'steps', 'ID': 'topicId'\n    }\n  },\n\n  'Devotionals': {\n    collection: 'devotionals',\n    docIdHeader: 'Date',\n    headerMap: {\n      'Date': 'date', 'Title': 'title', 'Theme': 'theme',\n      'Scripture': 'scripture', 'Reflection': 'reflection',\n      'Question': 'question', 'Prayer': 'prayer'\n    }\n  },\n\n  'Genealogy': {\n    collection: 'genealogy',\n    docIdHeader: 'ID',\n    headerMap: {\n      'Name': 'name', 'Title': 'title', 'Lifespan': 'lifespan',\n      'Meaning': 'meaning', 'Reference': 'reference', 'Bio': 'bio',\n      'Children': 'children', 'ID': 'personId'\n    }\n  },\n\n  'Heart': {\n    collection: 'heart',\n    docIdHeader: 'Question ID',\n    headerMap: {\n      'Question ID': 'questionId', 'Category': 'category',\n      'Chart Axis': 'chartAxis', 'Question': 'question',\n      'Prescription': 'prescription', 'Verse Reference': 'verseReference'\n    }\n  },\n\n  'Mirror': {\n    collection: 'mirror',\n    docIdHeader: null,\n    docIdPrefix: 'mir',\n    headerMap: {\n      'Category ID': 'categoryId', 'Category Title': 'categoryTitle',\n      'Color': 'color', 'Chart Label': 'chartLabel',\n      'Question ID': 'questionId', 'Question': 'question',\n      'Prescription': 'prescription', 'Scripture': 'scripture', 'Slug': 'slug'\n    }\n  },\n\n  'Quiz': {\n    collection: 'quiz',\n    docIdHeader: 'ID',\n    headerMap: {\n      'ID': 'quizId', 'Question': 'question',\n      'Option A': 'optionA', 'Option B': 'optionB',\n      'Option C': 'optionC', 'Option D': 'optionD',\n      'Correct Answer': 'correctAnswer', 'Reference': 'reference',\n      'Category': 'category', 'Difficulty': 'difficulty'\n    }\n  },\n\n  'Reading': {\n    collection: 'reading',\n    docIdHeader: null,\n    docIdPrefix: 'day',\n    headerMap: {\n      'Old Testament': 'oldTestament', 'New Testament': 'newTestament',\n      'Psalms': 'psalms', 'Proverbs': 'proverbs'\n    }\n  },\n\n  'Theology': {\n    collection: 'theology',\n    docIdHeader: null,\n    docIdPrefix: 'theo',\n    headerMap: {\n      'Category ID': 'categoryId', 'Category Title': 'categoryTitle',\n      'Category Intro': 'categoryIntro', 'Section ID': 'sectionId',\n      'Section Title': 'sectionTitle', 'Content': 'content'\n    }\n  },\n\n  'TheologyCategories': {\n    collection: 'theologyCategories',\n    docIdHeader: 'ID',\n    headerMap: {\n      'ID': 'id', 'Category ID': 'categoryId', 'Title': 'title',\n      'Subtitle': 'subtitle', 'Intro': 'intro', 'Icon': 'icon',\n      'Color Var': 'colorVar', 'Sort Order': 'sortOrder',\n      'Visible': 'visible', 'Status': 'status',\n      'Created At': 'createdAt', 'Updated At': 'updatedAt'\n    }\n  },\n\n  'Words': {\n    collection: 'words',\n    docIdHeader: \"Strong's\",\n    headerMap: {\n      'English': 'english', \"Strong's\": 'strongs',\n      'Original': 'original', 'Transliteration': 'transliteration',\n      'Definition': 'definition', 'Nuance': 'nuance',\n      'Testament': 'testament', 'Theme': 'theme',\n      'Usage Count': 'usageCount', 'Verses': 'verses'\n    }\n  }\n};\n\n\n/**\n * Reads Truth content tabs from the church's Google Sheet and seeds them\n * into Firestore under churches/{churchId}/{collection}/{docId}.\n *\n * Safe to re-run \u2014 deterministic doc IDs mean existing documents are\n * overwritten (not duplicated).\n *\n * Called automatically by setupFlockOS(), or run standalone to re-seed.\n */\nfunction seedFirestoreTruth() {\n  var churchId = _resolveFirestoreChurchId();\n  var token    = _getFirestoreAccessToken();\n  var ss       = SpreadsheetApp.openById(\n    PropertiesService.getScriptProperties().getProperty('SHEET_ID')\n  );\n\n  Logger.log('[SeedTruth] Church ID: ' + churchId);\n  Logger.log('[SeedTruth] Seeding Firestore Truth content...');\n\n  var totalDocs = 0;\n  var tabNames = Object.keys(TRUTH_FIRESTORE_MAP);\n\n  for (var t = 0; t < tabNames.length; t++) {\n    var tabName = tabNames[t];\n    var config  = TRUTH_FIRESTORE_MAP[tabName];\n    var sheet   = ss.getSheetByName(tabName);\n\n    if (!sheet) {\n      Logger.log('[SeedTruth]   \u26a0\ufe0f  Tab not found: ' + tabName + ' \u2014 skipping');\n      continue;\n    }\n\n    var data = sheet.getDataRange().getValues();\n    if (!data || data.length < 2) {\n      Logger.log('[SeedTruth]   \u26a0\ufe0f  ' + tabName + ' is empty \u2014 skipping');\n      continue;\n    }\n\n    // Row 0 = headers, rows 1+ = data\n    var headers = data[0].map(function(h) { return String(h || '').trim(); });\n\n    // Build header-index lookup\n    var hdrIdx = {};\n    for (var h = 0; h < headers.length; h++) {\n      if (config.headerMap[headers[h]]) {\n        hdrIdx[headers[h]] = h;\n      }\n    }\n\n    // Find the doc-ID column index (if using a header-based ID)\n    var idColIdx = -1;\n    if (config.docIdHeader) {\n      for (var hi = 0; hi < headers.length; hi++) {\n        if (headers[hi] === config.docIdHeader) { idColIdx = hi; break; }\n      }\n    }\n\n    // Collect all writes for this collection\n    var writes = [];\n    var rowCounter = 0;\n\n    for (var r = 1; r < data.length; r++) {\n      var row = data[r];\n\n      // Skip fully empty rows\n      var allEmpty = true;\n      for (var c = 0; c < row.length; c++) {\n        if (row[c] !== null && row[c] !== undefined && String(row[c]).trim() !== '') {\n          allEmpty = false; break;\n        }\n      }\n      if (allEmpty) continue;\n\n      rowCounter++;\n\n      // Determine document ID\n      var docId;\n      if (idColIdx >= 0 && row[idColIdx] !== null && String(row[idColIdx]).trim() !== '') {\n        docId = String(row[idColIdx]).trim();\n        // Date values \u2192 ISO string\n        if (row[idColIdx] instanceof Date) {\n          docId = Utilities.formatDate(row[idColIdx], 'UTC', 'yyyy-MM-dd');\n        }\n        // Sanitize for Firestore path (no slashes)\n        docId = docId.replace(/[\\/\\\\]/g, '_');\n      } else {\n        // Deterministic row-based ID\n        var prefix = config.docIdPrefix || tabName.toLowerCase().substring(0, 4);\n        docId = prefix + '_' + ('000' + rowCounter).slice(-3);\n      }\n\n      // Build Firestore fields object\n      var fields = {};\n      var hdrKeys = Object.keys(hdrIdx);\n      for (var k = 0; k < hdrKeys.length; k++) {\n        var sheetHeader = hdrKeys[k];\n        var fsField     = config.headerMap[sheetHeader];\n        var cellVal     = row[hdrIdx[sheetHeader]];\n        fields[fsField] = _toFirestoreValue(cellVal);\n      }\n\n      var docPath = config.collection + '/' + docId;\n      writes.push({\n        update: {\n          name: 'projects/' + FS_PROJECT_ID + '/databases/(default)/documents/' + docPath,\n          fields: fields\n        }\n      });\n    }\n\n    // Batch commit (max 450 per batch)\n    var committed = 0;\n    for (var i = 0; i < writes.length; i += 450) {\n      var batch = writes.slice(i, Math.min(i + 450, writes.length));\n      _firestoreBatchCommit(batch, token);\n      committed += batch.length;\n    }\n\n    totalDocs += committed;\n    Logger.log('[SeedTruth]   \u2705 ' + config.collection + ': ' + committed + ' docs');\n  }\n\n  Logger.log('[SeedTruth] \u2705 Firestore seed complete \u2014 ' + totalDocs + ' total documents');\n  return totalDocs;\n}\n\n\n/**\n * Converts a cell value to a Firestore REST API typed-value object.\n * Stores everything as stringValue for consistency with the Python importer.\n */\nfunction _toFirestoreValue(val) {\n  if (val === null || val === undefined) return { stringValue: '' };\n  if (typeof val === 'boolean') return { booleanValue: val };\n  if (val instanceof Date) {\n    return { stringValue: Utilities.formatDate(val, 'UTC', 'yyyy-MM-dd') };\n  }\n  var s = String(val).trim();\n  if (s.toLowerCase() === 'none') return { stringValue: '' };\n  return { stringValue: s };\n}\n\n\n/**\n * Creates or updates a single Firestore document via PATCH.\n */\nfunction _firestoreUpsertDoc(docPath, fields, accessToken) {\n  var url = 'https://firestore.googleapis.com/v1/projects/' + FS_PROJECT_ID +\n    '/databases/(default)/documents/' + docPath;\n\n  var resp = UrlFetchApp.fetch(url, {\n    method: 'patch',\n    contentType: 'application/json',\n    headers: { 'Authorization': 'Bearer ' + accessToken },\n    payload: JSON.stringify({ fields: fields }),\n    muteHttpExceptions: true\n  });\n\n  if (resp.getResponseCode() !== 200) {\n    Logger.log('[Firestore] PATCH error for ' + docPath + ': HTTP ' + resp.getResponseCode());\n    Logger.log(resp.getContentText().substring(0, 300));\n  }\n}\n\n\n/**\n * Commits a batch of writes to Firestore (max 500 per call).\n */\nfunction _firestoreBatchCommit(writes, accessToken) {\n  var url = 'https://firestore.googleapis.com/v1/projects/' + FS_PROJECT_ID +\n    '/databases/(default)/documents:commit';\n\n  var resp = UrlFetchApp.fetch(url, {\n    method: 'post',\n    contentType: 'application/json',\n    headers: { 'Authorization': 'Bearer ' + accessToken },\n    payload: JSON.stringify({ writes: writes }),\n    muteHttpExceptions: true\n  });\n\n  var code = resp.getResponseCode();\n  if (code !== 200) {\n    Logger.log('[Firestore] Batch commit error: HTTP ' + code);\n    Logger.log(resp.getContentText().substring(0, 500));\n    throw new Error('Firestore batch commit failed: HTTP ' + code);\n  }\n}\n\n\n// \u2500\u2500 Trigger Management \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n/**\n * Installs an hourly time-driven trigger for syncFirestoreToSheet.\n * Safe to re-run \u2014 removes any existing trigger first.\n */\nfunction installFirestoreSyncTrigger() {\n  // Remove existing triggers for this function\n  var triggers = ScriptApp.getProjectTriggers();\n  for (var i = 0; i < triggers.length; i++) {\n    if (triggers[i].getHandlerFunction() === 'syncFirestoreToSheet') {\n      ScriptApp.deleteTrigger(triggers[i]);\n    }\n  }\n\n  // Install new hourly trigger\n  ScriptApp.newTrigger('syncFirestoreToSheet')\n    .timeBased()\n    .everyHours(1)\n    .create();\n\n  Logger.log('\u2705 Hourly Firestore \u2192 Sheet sync trigger installed.');\n}\n\n/**\n * Removes the hourly sync trigger.\n */\nfunction removeFirestoreSyncTrigger() {\n  var triggers = ScriptApp.getProjectTriggers();\n  var removed = 0;\n  for (var i = 0; i < triggers.length; i++) {\n    if (triggers[i].getHandlerFunction() === 'syncFirestoreToSheet') {\n      ScriptApp.deleteTrigger(triggers[i]);\n      removed++;\n    }\n  }\n  Logger.log('Removed ' + removed + ' sync trigger(s).');\n}\n\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// LAZY TAB CREATION HELPER\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n/**\n * Returns the named sheet, creating it with a frozen header row if it does not\n * yet exist. Called by syncFirestoreToSheet so tabs are created on first data\n * arrival rather than during initial setup.\n *\n * @param {Spreadsheet} ss\n * @param {string}      tabName\n * @param {string[]}    headers  \u2014 written as row 1 when creating\n * @returns {Sheet}\n */\nfunction _getOrCreateSheet_(ss, tabName, headers) {\n  var sheet = ss.getSheetByName(tabName);\n  if (!sheet) {\n    sheet = ss.insertSheet(tabName);\n    if (headers && headers.length) {\n      sheet.getRange(1, 1, 1, headers.length).setValues([headers]);\n      sheet.setFrozenRows(1);\n    }\n    Logger.log('[FirestoreSync] Lazy-created tab: ' + tabName);\n  }\n  return sheet;\n}\n\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// TRUTH MASTER \u2014 FIRESTORE-TO-FIRESTORE REPLICATION\n//\n// FlockOS-Truth (flockos-truth) is the authoritative source for all shared\n// content (devotionals, theology, lexicon, quiz, etc.).\n//\n// replicateTruthFromMaster()  \u2014 copies Truth collections from FlockOS-Truth\n//   \u2192 this church's Firestore project (called during setupFlockOS).\n//\n// populateTruthMaster()  \u2014 ONE-TIME migration: reads Truth tabs from this\n//   church's Google Sheet and pushes them to FlockOS-Truth. Run this once from\n//   any existing church sheet that has the content, then use\n//   replicateTruthFromMaster() for all future church provisioning.\n//\n// Requires:\n//   TRUTH_SERVICE_ACCOUNT    \u2014 service account JSON for flockos-truth project\n//   FIREBASE_SERVICE_ACCOUNT \u2014 service account JSON for this church's project\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n\n/**\n * Returns an OAuth2 access token for the FlockOS-Truth Firestore project.\n * Uses TRUTH_SERVICE_ACCOUNT script property.\n */\nfunction _getTruthAccessToken() {\n  var props = PropertiesService.getScriptProperties();\n  var saJson = props.getProperty('TRUTH_SERVICE_ACCOUNT');\n  if (!saJson) throw new Error('TRUTH_SERVICE_ACCOUNT not set in Script Properties');\n\n  var sa = JSON.parse(saJson);\n  var now = Math.floor(Date.now() / 1000);\n\n  var header   = { alg: 'RS256', typ: 'JWT' };\n  var claimSet = {\n    iss:   sa.client_email,\n    scope: 'https://www.googleapis.com/auth/datastore',\n    aud:   'https://oauth2.googleapis.com/token',\n    iat:   now,\n    exp:   now + 3600\n  };\n\n  var b64H  = Utilities.base64EncodeWebSafe(JSON.stringify(header)).replace(/=+$/, '');\n  var b64C  = Utilities.base64EncodeWebSafe(JSON.stringify(claimSet)).replace(/=+$/, '');\n  var input = b64H + '.' + b64C;\n  var sig   = Utilities.base64EncodeWebSafe(\n    Utilities.computeRsaSha256Signature(input, sa.private_key)\n  ).replace(/=+$/, '');\n\n  var jwt = input + '.' + sig;\n\n  var resp = UrlFetchApp.fetch('https://oauth2.googleapis.com/token', {\n    method: 'post',\n    payload: { grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer', assertion: jwt },\n    muteHttpExceptions: true\n  });\n  var body = JSON.parse(resp.getContentText());\n  if (!body.access_token) throw new Error('Failed to get Truth access token: ' + resp.getContentText());\n  return body.access_token;\n}\n\n\n/**\n * Lists all documents from a top-level collection in any Firestore project.\n * Used to read Truth content from FlockOS-Truth.\n *\n * @param {string} projectId       \u2014 Firebase project ID (e.g. 'flockos-truth')\n * @param {string} collectionName  \u2014 top-level collection name\n * @param {string} accessToken\n * @returns {Array<{id: string, fields: Object}>}\n */\nfunction _firestoreListFromProject(projectId, collectionName, accessToken) {\n  var baseUrl = 'https://firestore.googleapis.com/v1/projects/' + projectId +\n    '/databases/(default)/documents/' + collectionName;\n\n  var allDocs = [];\n  var pageToken = null;\n\n  do {\n    var url = baseUrl + '?pageSize=300';\n    if (pageToken) url += '&pageToken=' + encodeURIComponent(pageToken);\n\n    var resp = UrlFetchApp.fetch(url, {\n      method: 'get',\n      headers: { 'Authorization': 'Bearer ' + accessToken },\n      muteHttpExceptions: true\n    });\n\n    var code = resp.getResponseCode();\n    if (code !== 200) {\n      Logger.log('[TruthSync] ERROR reading ' + collectionName + ' from ' + projectId + ': HTTP ' + code);\n      Logger.log(resp.getContentText().substring(0, 500));\n      break;\n    }\n\n    var body = JSON.parse(resp.getContentText());\n    var documents = body.documents || [];\n\n    for (var i = 0; i < documents.length; i++) {\n      var fsDoc = documents[i];\n      var nameParts = fsDoc.name.split('/');\n      allDocs.push({\n        id:     nameParts[nameParts.length - 1],\n        fields: fsDoc.fields || {}\n      });\n    }\n\n    pageToken = body.nextPageToken || null;\n  } while (pageToken);\n\n  return allDocs;\n}\n\n\n/**\n * Writes counseling/_catalog to a Firestore project with {items: [{id, title, icon, color}]}.\n * counselingDocs is an array of { id: string, fields: Firestore-typed-fields-object }.\n * Used by both replicateTruthFromMaster() and populateTruthMaster().\n */\nfunction _writeCounselingCatalog_(counselingDocs, projectId, accessToken) {\n  var items = [];\n  for (var i = 0; i < counselingDocs.length; i++) {\n    var d = counselingDocs[i];\n    if (d.id === '_catalog') continue;\n    var f = d.fields || {};\n    items.push({ mapValue: { fields: {\n      id:    { stringValue: d.id },\n      title: { stringValue: (f.title  && f.title.stringValue)  || '' },\n      icon:  { stringValue: (f.icon   && f.icon.stringValue)   || '' },\n      color: { stringValue: (f.color  && f.color.stringValue)  || '' }\n    }}});\n  }\n  var url = 'https://firestore.googleapis.com/v1/projects/' + projectId +\n    '/databases/(default)/documents/counseling/_catalog';\n  var resp = UrlFetchApp.fetch(url, {\n    method: 'patch',\n    contentType: 'application/json',\n    headers: { 'Authorization': 'Bearer ' + accessToken },\n    payload: JSON.stringify({ fields: {\n      items: { arrayValue: { values: items } }\n    }}),\n    muteHttpExceptions: true\n  });\n  if (resp.getResponseCode() !== 200) {\n    Logger.log('[CounselingCatalog] PATCH error: HTTP ' + resp.getResponseCode());\n    Logger.log(resp.getContentText().substring(0, 300));\n  } else {\n    Logger.log('[CounselingCatalog] \u2705 counseling/_catalog written \u2014 ' + items.length + ' stubs \u2192 ' + projectId);\n  }\n}\n\n\n/**\n * Replicates all Truth content from FlockOS-Truth Firestore \u2192 this church's\n * Firestore project under churches/{churchId}/{collection}.\n *\n * Called automatically by setupFlockOS(). Can also be run standalone to\n * refresh a church's Truth content after the master is updated.\n *\n * Replaces the old Sheet-based seedFirestoreTruth() approach.\n *\n * Requires:\n *   TRUTH_SERVICE_ACCOUNT    \u2014 read FlockOS-Truth\n *   FIREBASE_SERVICE_ACCOUNT \u2014 write to this church's project\n */\nfunction replicateTruthFromMaster() {\n  var churchId    = _resolveFirestoreChurchId();\n  var churchToken = _getFirestoreAccessToken();\n  var truthToken  = _getTruthAccessToken();\n\n  Logger.log('[TruthSync] Replicating Truth content from ' + TRUTH_PROJECT_ID + ' \u2192 ' + FS_PROJECT_ID);\n\n  var totalDocs = 0;\n  var collections = [\n    'apologetics', 'books', 'counseling', 'devotionals', 'genealogy',\n    'heart', 'mirror', 'quiz', 'reading', 'theology', 'theologyCategories', 'words'\n  ];\n\n  var counselingDocs = null;\n\n  for (var c = 0; c < collections.length; c++) {\n    var collectionName = collections[c];\n\n    // Read all docs from the master Truth project (top-level collections)\n    var docs = _firestoreListFromProject(TRUTH_PROJECT_ID, collectionName, truthToken);\n\n    if (!docs.length) {\n      Logger.log('[TruthSync]   \u26a0\ufe0f  ' + collectionName + ': 0 docs in master \u2014 skipping');\n      continue;\n    }\n\n    // Capture counseling docs for catalog write below\n    if (collectionName === 'counseling') { counselingDocs = docs; }\n\n    // Build batch writes targeting this church's Firestore\n    var writes = [];\n    for (var d = 0; d < docs.length; d++) {\n      var doc = docs[d];\n      var docPath = collectionName + '/' + doc.id;\n      writes.push({\n        update: {\n          name: 'projects/' + FS_PROJECT_ID + '/databases/(default)/documents/' + docPath,\n          fields: doc.fields\n        }\n      });\n    }\n\n    // Commit in batches of 450\n    var committed = 0;\n    for (var i = 0; i < writes.length; i += 450) {\n      _firestoreBatchCommit(writes.slice(i, Math.min(i + 450, writes.length)), churchToken);\n      committed += Math.min(450, writes.length - i);\n    }\n\n    totalDocs += committed;\n    Logger.log('[TruthSync]   \u2705 ' + collectionName + ': ' + committed + ' docs');\n  }\n\n  // Write counseling/_catalog stub doc for lazy-load\n  if (counselingDocs) { _writeCounselingCatalog_(counselingDocs, FS_PROJECT_ID, churchToken); }\n\n  Logger.log('[TruthSync] \u2705 Replication complete \u2014 ' + totalDocs + ' total documents \u2192 ' + FS_PROJECT_ID);\n  return totalDocs;\n}\n\n\n/**\n * Backward-compatible alias. Old calls to seedFirestoreTruth() now route\n * through replicateTruthFromMaster(). If TRUTH_SERVICE_ACCOUNT is not set,\n * logs a warning and returns 0 (non-fatal).\n */\nfunction seedFirestoreTruth() {\n  var saJson = PropertiesService.getScriptProperties().getProperty('TRUTH_SERVICE_ACCOUNT');\n  if (!saJson) {\n    Logger.log('[TruthSync] \u26a0\ufe0f  TRUTH_SERVICE_ACCOUNT not set \u2014 skipping Truth replication.');\n    Logger.log('[TruthSync]    Set TRUTH_SERVICE_ACCOUNT to the flockos-truth service account JSON,');\n    Logger.log('[TruthSync]    then run replicateTruthFromMaster() to seed Truth content.');\n    return 0;\n  }\n  return replicateTruthFromMaster();\n}\n\n\n/**\n * ONE-TIME MIGRATION: reads all 12 Truth content tabs from this church's\n * Google Sheet and pushes them to FlockOS-Truth Firestore as top-level\n * collections (not under churches/{id}/).\n *\n * Run this ONCE from the FlockOS master GAS project (which has the populated\n * Truth tabs). After this, all future churches use replicateTruthFromMaster().\n *\n * Requires TRUTH_SERVICE_ACCOUNT in Script Properties.\n */\nfunction populateTruthMaster() {\n  var props      = PropertiesService.getScriptProperties();\n  var sheetId    = (props.getProperty('SHEET_ID') || '').trim();\n  if (!sheetId) throw new Error('SHEET_ID not set in Script Properties');\n\n  var truthToken = _getTruthAccessToken();\n  var ss         = SpreadsheetApp.openById(sheetId);\n\n  Logger.log('[TruthMaster] Populating FlockOS-Truth (' + TRUTH_PROJECT_ID + ') from sheet ' + sheetId);\n\n  var totalDocs = 0;\n  var tabNames  = Object.keys(TRUTH_FIRESTORE_MAP);\n  var counselingStubDocs = null;\n\n  for (var t = 0; t < tabNames.length; t++) {\n    var tabName    = tabNames[t];\n    var config     = TRUTH_FIRESTORE_MAP[tabName];\n    var sheet      = ss.getSheetByName(tabName);\n\n    if (!sheet) {\n      Logger.log('[TruthMaster]   \u26a0\ufe0f  Tab not found: ' + tabName + ' \u2014 skipping');\n      continue;\n    }\n\n    var data = sheet.getDataRange().getValues();\n    if (!data || data.length < 2) {\n      Logger.log('[TruthMaster]   \u26a0\ufe0f  ' + tabName + ' is empty \u2014 skipping');\n      continue;\n    }\n\n    var headers = data[0].map(function(h) { return String(h || '').trim(); });\n    var hdrIdx  = {};\n    for (var h = 0; h < headers.length; h++) {\n      if (config.headerMap[headers[h]]) hdrIdx[headers[h]] = h;\n    }\n\n    var idColIdx = -1;\n    if (config.docIdHeader) {\n      for (var hi = 0; hi < headers.length; hi++) {\n        if (headers[hi] === config.docIdHeader) { idColIdx = hi; break; }\n      }\n    }\n\n    var writes   = [];\n    var rowCount = 0;\n\n    for (var r = 1; r < data.length; r++) {\n      var row = data[r];\n      var allEmpty = true;\n      for (var c = 0; c < row.length; c++) {\n        if (row[c] !== null && row[c] !== undefined && String(row[c]).trim() !== '') { allEmpty = false; break; }\n      }\n      if (allEmpty) continue;\n      rowCount++;\n\n      var docId;\n      if (idColIdx >= 0 && row[idColIdx] !== null && String(row[idColIdx]).trim() !== '') {\n        docId = String(row[idColIdx] instanceof Date\n          ? Utilities.formatDate(row[idColIdx], 'UTC', 'yyyy-MM-dd')\n          : row[idColIdx]).trim().replace(/[\\/\\\\]/g, '_');\n      } else {\n        docId = (config.docIdPrefix || tabName.toLowerCase().substring(0, 4)) + '_' + ('000' + rowCount).slice(-3);\n      }\n\n      var fields  = {};\n      var hdrKeys = Object.keys(hdrIdx);\n      for (var k = 0; k < hdrKeys.length; k++) {\n        fields[config.headerMap[hdrKeys[k]]] = _toFirestoreValue(row[hdrIdx[hdrKeys[k]]]);\n      }\n\n      // Top-level collection in FlockOS-Truth (no churches/{id}/ prefix)\n      writes.push({\n        update: {\n          name: 'projects/' + TRUTH_PROJECT_ID + '/databases/(default)/documents/' + config.collection + '/' + docId,\n          fields: fields\n        }\n      });\n    }\n\n    // Commit in batches of 450 using the Truth project token\n    // (re-use _firestoreBatchCommit but against Truth project URL)\n    var committed = 0;\n    for (var i = 0; i < writes.length; i += 450) {\n      var batch = writes.slice(i, Math.min(i + 450, writes.length));\n      var url   = 'https://firestore.googleapis.com/v1/projects/' + TRUTH_PROJECT_ID +\n        '/databases/(default)/documents:commit';\n      var resp  = UrlFetchApp.fetch(url, {\n        method: 'post',\n        contentType: 'application/json',\n        headers: { 'Authorization': 'Bearer ' + truthToken },\n        payload: JSON.stringify({ writes: batch }),\n        muteHttpExceptions: true\n      });\n      if (resp.getResponseCode() !== 200) {\n        Logger.log('[TruthMaster] Batch commit error: HTTP ' + resp.getResponseCode());\n        Logger.log(resp.getContentText().substring(0, 500));\n        throw new Error('populateTruthMaster batch commit failed');\n      }\n      committed += batch.length;\n    }\n\n    totalDocs += committed;\n    Logger.log('[TruthMaster]   \u2705 ' + config.collection + ': ' + committed + ' docs \u2192 ' + TRUTH_PROJECT_ID);\n\n    // Capture counseling docs for catalog write below\n    if (config.collection === 'counseling') {\n      counselingStubDocs = [];\n      for (var w = 0; w < writes.length; w++) {\n        var wName = writes[w].update.name;\n        counselingStubDocs.push({ id: wName.split('/').pop(), fields: writes[w].update.fields });\n      }\n    }\n  }\n\n  // Write counseling/_catalog stub doc for lazy-load\n  if (counselingStubDocs) { _writeCounselingCatalog_(counselingStubDocs, TRUTH_PROJECT_ID, truthToken); }\n\n  Logger.log('[TruthMaster] \u2705 Done \u2014 ' + totalDocs + ' total documents written to FlockOS-Truth.');\n  Logger.log('[TruthMaster]    Future churches can now call replicateTruthFromMaster() instead of reading from the Sheet.');\n  return totalDocs;\n}\n\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// CHURCH DATA MIGRATION \u2014 Sheet \u2192 Firestore\n//\n// Migrates existing church data from the Google Sheet into Firestore for the\n// first time.  Uses SYNC_COLLECTIONS (same mapping as syncFirestoreToSheet) so\n// every collection is kept in sync automatically.\n//\n// Run once per church during initial Firestore setup, AFTER\n// testFirestoreConnection() confirms the project is reachable.\n//\n// Safe to re-run \u2014 rows with an existing Firestore doc ID are overwritten\n// (not duplicated).  Rows without an ID in column A get a new generated ID\n// which is written back into the sheet so future syncs can match them.\n//\n// Requires: FIREBASE_SERVICE_ACCOUNT (or FIRESTORE_SERVICE_ACCOUNT)\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n/**\n * Migrates all SYNC_COLLECTIONS tabs from the church's Google Sheet \u2192\n * Firestore under {collection}/{docId}  (root-level \u2014 each project IS the church).\n *\n * Run from the GAS editor dropdown to seed Firestore with existing sheet data.\n */\nfunction migrateSheetToFirestore() {\n  var props    = PropertiesService.getScriptProperties();\n  var sheetId  = (props.getProperty('SHEET_ID') || '').trim();\n  if (!sheetId) throw new Error('SHEET_ID not set in Script Properties');\n\n  var token    = _getFirestoreAccessToken();\n  var ss       = SpreadsheetApp.openById(sheetId);\n\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n  Logger.log('  FlockOS \u2014 Sheet \u2192 Firestore Migration');\n  Logger.log('  Project : ' + FS_PROJECT_ID);\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n\n  var grandTotal = 0;\n  var collNames  = Object.keys(SYNC_COLLECTIONS);\n\n  for (var c = 0; c < collNames.length; c++) {\n    var collName = collNames[c];\n    var config   = SYNC_COLLECTIONS[collName];\n    var sheet    = ss.getSheetByName(config.tab);\n\n    if (!sheet) {\n      Logger.log('  \u26a0\ufe0f  Tab not found: ' + config.tab + ' \u2014 skipping');\n      continue;\n    }\n\n    var lastRow = sheet.getLastRow();\n    if (lastRow < 2) {\n      Logger.log('  \u26a0\ufe0f  ' + config.tab + ' is empty \u2014 skipping');\n      continue;\n    }\n\n    // Read all data including headers\n    var allData  = sheet.getRange(1, 1, lastRow, sheet.getLastColumn()).getValues();\n    var sheetHdrs = allData[0].map(function(h) { return String(h || '').trim(); });\n\n    // Build header \u2192 field index map using SYNC_COLLECTIONS definition\n    // (headers[i] \u2192 fields[i] are parallel arrays)\n    var hdrToField = {};\n    for (var f = 0; f < config.fields.length; f++) {\n      if (config.headers[f]) {\n        hdrToField[config.headers[f]] = config.fields[f];\n      }\n    }\n\n    // Find column indexes in the actual sheet\n    var colMap = {};   // fieldName \u2192 column index in sheet\n    for (var h = 0; h < sheetHdrs.length; h++) {\n      var fieldName = hdrToField[sheetHdrs[h]];\n      if (fieldName) colMap[fieldName] = h;\n    }\n\n    // Column A is always the doc ID column ('id' field / 'ID' header)\n    var idColIdx = 0;\n    if (sheetHdrs[0] !== 'ID' && sheetHdrs[0] !== 'id') {\n      idColIdx = sheetHdrs.indexOf('ID');\n      if (idColIdx === -1) idColIdx = sheetHdrs.indexOf('id');\n      if (idColIdx === -1) idColIdx = 0;\n    }\n\n    var writes       = [];\n    var idWritebacks = [];  // { rowIdx, docId } \u2014 new IDs to write back to sheet\n    var rowCount     = 0;\n\n    for (var r = 1; r < allData.length; r++) {\n      var row = allData[r];\n\n      // Skip fully empty rows\n      var allEmpty = true;\n      for (var ci = 0; ci < row.length; ci++) {\n        if (row[ci] !== null && row[ci] !== undefined && String(row[ci]).trim() !== '') {\n          allEmpty = false; break;\n        }\n      }\n      if (allEmpty) continue;\n      rowCount++;\n\n      // Determine doc ID \u2014 use existing value in ID column, or generate one\n      var docId = String(row[idColIdx] || '').trim();\n      if (!docId) {\n        // Generate a stable ID: collectionPrefix + timestamp + row index\n        docId = collName.substring(0, 4) + '_' + Date.now() + '_' + rowCount;\n        idWritebacks.push({ rowIdx: r, colIdx: idColIdx + 1, docId: docId });\n      }\n      // Sanitize for Firestore path\n      docId = docId.replace(/[\\/\\\\]/g, '_');\n\n      // Build Firestore fields object\n      var fields = {};\n      var fieldNames = Object.keys(colMap);\n      for (var fi = 0; fi < fieldNames.length; fi++) {\n        var fn  = fieldNames[fi];\n        var val = row[colMap[fn]];\n        fields[fn] = _toFirestoreValue(val);\n      }\n      // Always store the doc ID as the 'id' field too\n      fields['id'] = { stringValue: docId };\n\n      var docPath = collName + '/' + docId;\n      writes.push({\n        update: {\n          name: 'projects/' + FS_PROJECT_ID + '/databases/(default)/documents/' + docPath,\n          fields: fields\n        }\n      });\n    }\n\n    // Write back any newly generated IDs to the sheet\n    for (var wb = 0; wb < idWritebacks.length; wb++) {\n      sheet.getRange(idWritebacks[wb].rowIdx + 1, idWritebacks[wb].colIdx).setValue(idWritebacks[wb].docId);\n    }\n\n    // Batch commit (max 450 per batch)\n    var committed = 0;\n    for (var i = 0; i < writes.length; i += 450) {\n      _firestoreBatchCommit(writes.slice(i, Math.min(i + 450, writes.length)), token);\n      committed += Math.min(450, writes.length - i);\n    }\n\n    grandTotal += committed;\n    Logger.log('  \u2705 ' + collName + ' (' + config.tab + '): ' + committed + ' docs');\n  }\n\n  SpreadsheetApp.flush();\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n  Logger.log('  \u2705 Migration complete \u2014 ' + grandTotal + ' total documents');\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n  return grandTotal;\n}\n\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// REAL-TIME SYNC SETUP\n//\n// Writes the settings/sync document that the Cloud Function reads to know\n// where to POST Firestore change events.\n//\n// Run this ONCE per church after:\n//   1. The GAS project is deployed as a Web App (Execute as: Me, Access: Anyone)\n//   2. The following Script Properties are set:\n//        GAS_ENDPOINT  \u2014 the Web App URL  (e.g. https://script.google.com/macros/s/.../exec)\n//        SYNC_SECRET   \u2014 a random shared secret (must match what the Cloud Function sends)\n//\n// The Cloud Function (functions/index.js) reads:\n//   settings/sync \u2192 { gasEndpoint, syncSecret }\n// and POSTs to gasEndpoint?action=sync.write&syncSecret=<value> on each write.\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n/**\n * Writes the real-time sync settings document for this church into Firestore.\n * Run once from the GAS editor after deploying the Web App.\n *\n * Required Script Properties:\n *   GAS_ENDPOINT  \u2014 the deployed Web App URL for this church's GAS project\n *   SYNC_SECRET   \u2014 shared secret used to authenticate Cloud Function POSTs\n */\nfunction setupFirestoreSync() {\n  var props      = PropertiesService.getScriptProperties();\n  var endpoint   = (props.getProperty('GAS_ENDPOINT') || '').trim();\n  var syncSecret = (props.getProperty('SYNC_SECRET')  || '').trim();\n\n  if (!endpoint)   throw new Error('GAS_ENDPOINT not set in Script Properties');\n  if (!syncSecret) throw new Error('SYNC_SECRET not set in Script Properties');\n\n  var token = _getFirestoreAccessToken();\n\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n  Logger.log('  FlockOS \u2014 Real-Time Sync Setup');\n  Logger.log('  Project  : ' + FS_PROJECT_ID);\n  Logger.log('  Endpoint : ' + endpoint);\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n\n  // Write the sync settings document\n  var docPath = 'settings/sync';\n  var url = 'https://firestore.googleapis.com/v1/projects/' + FS_PROJECT_ID +\n    '/databases/(default)/documents/' + docPath;\n\n  var resp = UrlFetchApp.fetch(url, {\n    method: 'patch',\n    contentType: 'application/json',\n    headers: { 'Authorization': 'Bearer ' + token },\n    payload: JSON.stringify({\n      fields: {\n        gasEndpoint: { stringValue: endpoint },\n        syncSecret:  { stringValue: syncSecret },\n        updatedAt:   { stringValue: new Date().toISOString() }\n      }\n    }),\n    muteHttpExceptions: true\n  });\n\n  var code = resp.getResponseCode();\n  if (code === 200) {\n    Logger.log('  \u2705 Sync settings written \u2192 settings/sync');\n    Logger.log('  The Cloud Function will now POST Firestore changes to:');\n    Logger.log('  ' + endpoint + '?action=sync.write&syncSecret=...');\n  } else {\n    Logger.log('  \u274c Failed: HTTP ' + code);\n    Logger.log(resp.getContentText().substring(0, 300));\n  }\n\n  Logger.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');\n}\n";
window.BEZALEL_FIRESTORESYNC_GS_LINES = 1424;
